#include "qp/data/quote.hpp"
namespace qp::data { Price Quote::mid() const noexcept { return Price{(bid_price.value+ask_price.value)/2.0}; } double Quote::spread() const noexcept { return ask_price.value-bid_price.value; } double Quote::spread_bps() const noexcept { auto m=mid().value; return m>0.0 ? (spread()/m)*10000.0 : 0.0; } Result<void> Quote::validate() const { if(symbol.empty()) return Err(Error{ErrorCode::InvalidData,"quote symbol empty"}); if(!bid_price.is_positive() || !ask_price.is_positive()) return Err(Error{ErrorCode::InvalidData,"quote prices must be positive"}); if(!bid_quantity.is_non_negative() || !ask_quantity.is_non_negative()) return Err(Error{ErrorCode::InvalidData,"quote quantities must be non-negative"}); if(bid_price.value > ask_price.value) return Err(Error{ErrorCode::InvalidData,"crossed quote"}); return Ok(); } }
